prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?participant) AS ?participantCount)
       (SAMPLE(COALESCE(?participantName, STR(?participant))) AS ?exampleParticipantName)
       (SAMPLE(?modelName) AS ?exampleModelName)
WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }

  OPTIONAL { ?model tai:originalId ?oid . }
  OPTIONAL { ?model tai:normalizedId ?nid . }

  FILTER(
    (BOUND(?oid) && CONTAINS(LCASE(STR(?oid)), LCASE("0cad2ceffcad428aab5664a733b078e6")))
    ||
    (BOUND(?nid) && CONTAINS(LCASE(STR(?nid)), LCASE("0cad2ceffcad428aab5664a733b078e6")))
  )

  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?model .

  OPTIONAL { ?participant bbo:name ?participantName . }
}
GROUP BY ?participantCount
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?participant) AS ?participantCount)
       (SAMPLE(COALESCE(?participantName, STR(?participant))) AS ?exampleParticipantName)
       (SAMPLE(?modelName) AS ?exampleModelName)
WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }

  FILTER(
    CONTAINS(LCASE(STR(?model)), LCASE("0cad2ceffcad428aab5664a733b078e6"))
    ||
    EXISTS { ?model tai:originalId ?x . FILTER(CONTAINS(LCASE(STR(?x)), LCASE("0cad2ceffcad428aab5664a733b078e6"))) }
    ||
    EXISTS { ?model tai:normalizedId ?y . FILTER(CONTAINS(LCASE(STR(?y)), LCASE("0cad2ceffcad428aab5664a733b078e6"))) }
  )

  ?choreo tai:belongsTo ?model .
  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo .
  OPTIONAL { ?participant bbo:name ?participantName . }
}
GROUP BY ?participantCount
LIMIT 25
